// Build the daily digest from the three table reads
const kpis = {};
for (const it of $('Get KPIs').all()) {
  if (it.json && it.json.metric) kpis[it.json.metric] = it.json;
}
const pending = $('Get Pending Reviews').all().filter(i => i.json && i.json.pair_id !== undefined);
const alerts = $('Get Unsent Alerts').all().filter(i => i.json && i.json.supplier_id !== undefined);

const fmt = n => Number(n || 0).toLocaleString('en-US');
const lines = [];
lines.push('\ud83d\udc8a *Pharma Sales \u2014 Daily Digest*');
lines.push('');
lines.push(`\ud83d\udcb0 Total revenue: EGP ${fmt(kpis.total_revenue_egp?.value_num)}`);
lines.push(`\ud83e\uddfe Transactions: ${fmt(kpis.total_transactions?.value_num)}`);
lines.push(`\ud83c\udfc6 Top product: ${kpis.top_product?.value_text || 'n/a'}`);
lines.push(`\ud83e\udd47 Top rep: ${kpis.top_rep?.value_text || 'n/a'} (EGP ${fmt(kpis.top_rep?.value_num)})`);
lines.push(`\ud83c\udfea Top pharmacy: ${kpis.top_pharmacy?.value_text || 'n/a'}`);
lines.push(`\ud83d\udce6 Top supplier: #${kpis.top_supplier?.value_text || '?'} (EGP ${fmt(kpis.top_supplier?.value_num)})`);
lines.push('');
lines.push(`\ud83d\udd0d HITL queue: *${pending.length}* pairs awaiting review \u2014 send /review to the review bot`);

if (alerts.length > 0) {
  lines.push('');
  lines.push(`\u26a0\ufe0f *${alerts.length} anomaly alert(s):*`);
  const top = alerts.sort((a, b) => Math.abs(b.json.rzscore) - Math.abs(a.json.rzscore)).slice(0, 5);
  for (const a of top) {
    const e = a.json.direction === 'DROP' ? '\ud83d\udd3b' : '\ud83d\udd3a';
    lines.push(`${e} supplier ${a.json.supplier_id}, week ${a.json.week}: ${a.json.direction} (EGP ${fmt(a.json.total_amount)}, z=${a.json.rzscore})`);
  }
  if (alerts.length > 5) lines.push(`\u2026 and ${alerts.length - 5} more in the alerts table`);
} else {
  lines.push('');
  lines.push('\u2705 No new anomalies.');
}

return [{ json: { message_text: lines.join('\n'), n_alerts: alerts.length } }];
